#include <iostream>
using namespace std;

class Base {
public:
 virtual void show() { // Virtual function
 cout << "Base show()" << endl;
 }
 virtual ~Base() { // Virtual destructor
 cout << "Base destructor" << endl;
 }
};

class Derived : public Base {
public:
 void show() override { // Overrides Base::show()
 cout << "Derived show()" << endl;
 }
 ~Derived() {
 cout << "Derived destructor" << endl;
 }
};

int main() {
 Base *ptr = new Derived(); // Upcasting
 ptr->show(); // Calls Derived::show() - polymorphism
 delete ptr; // Calls both destructors in correct order

 return 0;
}

#include <iostream>
using namespace std;

class Shape {
protected:
 double x, y;
public:
 Shape(double a = 0, double b = 0) : x(a), y(b) {}
 virtual double area() = 0; // Pure virtual function
 virtual ~Shape() {}
};

class Rectangle : public Shape {
public:
 Rectangle(double l, double b) : Shape(l, b) {}
 double area() override {
 return x * y;
 }
};

class Circle : public Shape {
public:
 Circle(double r) : Shape(r, 0) {}
 double area() override {
 return 3.14 * x * x;
 }
};

int main() {
 // Shape s; // ERROR: Cannot instantiate abstract class
 Shape *arr[2];
 arr[0] = new Rectangle(5, 3);
 arr[1] = new Circle(4);

 cout << "Rectangle Area: " << arr[0]->area() << endl;
 cout << "Circle Area: " << arr[1]->area() << endl;

 delete arr[0];
 delete arr[1];
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 virtual void display() { // Must be virtual for RTTI
 cout << "Base display" << endl;
 }
 virtual ~Base() {}
};

class Derived : public Base {
public:
 void display() override {
 cout << "Derived display" << endl;
 }
 void derivedOnly() {
 cout << "Derived specific method" << endl;
 }
};

int main() {
 Base *bptr = new Derived(); // Base pointer to Derived

 // Unsafe downcast - compiles but dangerous
 // Derived *dptr = (Derived *)bptr; 

 // Safe downcast using dynamic_cast
 Derived *dptr = dynamic_cast<Derived *>(bptr);

 if (dptr) {
 cout << "Downcast successful!" << endl;
 dptr->derivedOnly();
 } else {
 cout << "Downcast failed!" << endl;
 }

 // Failed downcast example
 Base *bptr2 = new Base();
 Derived *dptr2 = dynamic_cast<Derived *>(bptr2);

 if (!dptr2) {
 cout << "Second downcast failed (expected)" << endl;
 }

 delete bptr;
 delete bptr2;
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int a;
 Base(int x) : a(x) {}
 void show() {
 cout << "Base: a = " << a << endl;
 }
};

class Derived : public Base {
public:
 int b;
 Derived(int x, int y) : Base(x), b(y) {}
 void show() {
 cout << "Derived: a = " << a << ", b = " << b << endl;
 }
};

int main() {
 Derived d(10, 20);

 cout << "Original Derived object:" << endl;
 d.show(); // Prints both a and b

 cout << "\nAfter slicing (assigned to Base by value):" << endl;
 Base b = d; // Object slicing happens here!
 b.show(); // Only Base portion exists now

 cout << "\nUsing pointer (no slicing):" << endl;
 Base *ptr = &d;
 ptr->show(); // Still calls Derived::show() if virtual

 return 0;
